parameters.jsCode:
try {
  const input = $input.first();
  if (!input || !input.json) {
    return [{ json: {
      owner_message: '⚠️ *שגיאה*\n\nלא התקבל מידע על שינוי סטטוס.',
      customer_message: '',
      should_notify_customer: false,
      should_notify_owner: true
    }}];
  }

  const data = input.json;
  const name = data.name || 'לא ידוע';
  const phone = data.phone || '';
  const category = data.category || '';
  const source = data.source_page || '';
  const newStatus = data.new_status || '';
  const prevStatus = data.previous_status || '';
  const chatId = data.chat_id || '';
  const notInterestedReason = data.not_interested_reason || '';
  const agentName = data.agent_name || 'לא צוין';
  const notes = data.notes || '';

  const statusLabels = {
    'new': 'חדש',
    'contacted': 'נוצר קשר',
    'no_answer': 'לא ענה',
    'in_progress': 'בטיפול',
    'qualified': 'מתאים',
    'closing_process': 'בתהליך סגירה',
    'send_marketing_material': 'נשלח חומר שיווקי',
    'not_interested': 'לא מעוניין',
    'converted': 'הומר ללקוח',
    'closed': 'נסגר',
    'follow_up': 'מעקב',
    'waiting': 'ממתין',
    'completed': 'הושלם'
  };

  const notInterestedReasons = {
    'already_has_osek': 'כבר יש עוסק',
    'not_now': 'לא עכשיו',
    'looking_for_different_service': 'מחפש שירות אחר',
    'price_too_high': 'מחיר גבוה מדי',
    'prefers_other_accountant': 'מעדיף רואה חשבון אחר',
    'decided_not_to_open_business': 'החליט לא לפתוח עסק',
    'going_with_osek_morsha': 'הולך עם עוסק מורשה',
    'doing_it_alone': 'עושה לבד',
    'employer_doesnt_allow': 'המעסיק לא מאשר',
    'waiting_for_discharge': 'ממתין לשחרור',
    'too_complicated': 'מסובך מדי'
  };

  const statusHe = statusLabels[newStatus] || newStatus;
  const prevStatusHe = statusLabels[prevStatus] || prevStatus;

  let emoji = '📄';
  if (newStatus === 'converted' || newStatus === 'completed') emoji = '✅';
  if (newStatus === 'not_interested') emoji = '❌';
  if (newStatus === 'in_progress' || newStatus === 'contacted') emoji = '📵';
  if (newStatus === 'follow_up' || newStatus === 'closing_process') emoji = '📅';
  if (newStatus === 'waiting' || newStatus === 'no_answer') emoji = '⏳';
  if (newStatus === 'qualified') emoji = '⭐';
  if (newStatus === 'send_marketing_material') emoji = '📨';
  if (newStatus === 'closed') emoji = '📁';

  let ownerMessage = `${emoji} *שינוי סטטוס ליד*\n\n👤 ${name}\n📞 ${phone}\n📂 ${category}\n📄 ${source}\n🧑‍💼 נציג: ${agentName}\n\n📊 סטטוס: ${prevStatusHe} → ${statusHe}`;

  if (newStatus === 'not_interested' && notInterestedReason) {
    const reasonHe = notInterestedReasons[notInterestedReason] || notInterestedReason;
    ownerMessage += `\n\n❌ *סיבה:* ${reasonHe}`;
  }

  if (notes) {
    ownerMessage += `\n📝 הערות: ${notes}`;
  }

  let customerMessage = '';
  if (newStatus === 'converted' || newStatus === 'completed') {
    customerMessage = `היי ${name}! רצינו לעדכן שהטיפול בפנייתך הושלם בהצלחה. תודה שבחרת ב-Perfect 1! אם תצטרך עזרה נוספת, אנחנו כאן.`;
  } else if (newStatus === 'follow_up' || newStatus === 'closing_process') {
    customerMessage = `היי ${name}, ניצור איתך קשר בקרוב 🕐`;
  } else if (newStatus === 'no_answer') {
    customerMessage = `היי ${name}, ניסינו ליצור איתך קשר. נחזור אליך שוב בקרוב 📞`;
  } else if (newStatus === 'send_marketing_material') {
    customerMessage = `היי ${name}, שלחנו לך חומר שיווקי על כל המידע שצריך. מוזמן/ת לעיין וליצור קשר על כל שאלה 📄`;
  }

  return [{ json: {
    ...data,
    owner_message: ownerMessage,
    customer_message: customerMessage,
    should_notify_customer: customerMessage !== '',
    should_notify_owner: true
  }}];
} catch (error) {
  return [{ json: {
    owner_message: `⚠️ *שגיאה בעיבוד שינוי סטטוס*\n\n${error.message}`,
    customer_message: '',
    should_notify_customer: false,
    should_notify_owner: true
  }}];
}

